import{_ as a,c as o,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Apêndice: Guia de Referência e Migração | oh-my-opencode","description":"Domine as opções de configuração do oh-my-opencode, compatibilidade com Claude Code e servidores MCP integrados. Este guia de referência aborda etapas de migração e recursos de pesquisa para personalizar seu ambiente OpenCode e estender fluxos de trabalho com IA.","frontmatter":{"title":"Apêndice: Guia de Referência e Migração | oh-my-opencode","sidebarTitle":"Configuração e Migração","subtitle":"Apêndice: Guia de Referência e Compatibilidade","description":"Domine as opções de configuração do oh-my-opencode, compatibilidade com Claude Code e servidores MCP integrados. Este guia de referência aborda etapas de migração e recursos de pesquisa para personalizar seu ambiente OpenCode e estender fluxos de trabalho com IA.","tags":["Apêndice","Referência"],"order":170},"headers":[],"relativePath":"pt/code-yeongyu/oh-my-opencode/appendix/index.md","filePath":"pt/code-yeongyu/oh-my-opencode/appendix/index.md"}'),d={name:"pt/code-yeongyu/oh-my-opencode/appendix/index.md"};function n(s,e,t,c,l,p){return r(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="apendice-guia-de-referencia-e-compatibilidade" tabindex="-1">Apêndice: Guia de Referência e Compatibilidade <a class="header-anchor" href="#apendice-guia-de-referencia-e-compatibilidade" aria-label="Permalink to &quot;Apêndice: Guia de Referência e Compatibilidade&quot;">​</a></h1><p>Este capítulo contém materiais de referência detalhados e diretrizes de compatibilidade para o <strong>oh-my-opencode</strong>, cobrindo documentação completa de configuração, suporte de migração do Claude Code e introduções detalhadas aos servidores de extensão integrados.</p><h2 id="conteudo-do-capitulo" tabindex="-1">Conteúdo do Capítulo <a class="header-anchor" href="#conteudo-do-capitulo" aria-label="Permalink to &quot;Conteúdo do Capítulo&quot;">​</a></h2><p>Este capítulo inclui três seções importantes:</p><table tabindex="0"><thead><tr><th>Subpágina</th><th>Descrição</th><th>Dificuldade</th></tr></thead><tbody><tr><td><a href="./claude-code-compatibility/">Compatibilidade com Claude Code</a></td><td>Guia completo para migrar do Claude Code para o OpenCode, incluindo mecanismos de compatibilidade para Commands, Skills, Agents, MCPs e Hooks</td><td>⭐⭐</td></tr><tr><td><a href="./configuration-reference/">Referência de Configuração</a></td><td>Documentação completa do Schema para arquivos de configuração do oh-my-opencode, cobrindo todos os campos, tipos e valores padrão</td><td>⭐⭐⭐</td></tr><tr><td><a href="./builtin-mcps/">MCPs Integrados</a></td><td>Recursos e uso de 3 servidores MCP integrados (Exa Websearch, Context7, Grep.app)</td><td>⭐⭐</td></tr></tbody></table><h2 id="caminhos-de-aprendizagem-recomendados" tabindex="-1">Caminhos de Aprendizagem Recomendados <a class="header-anchor" href="#caminhos-de-aprendizagem-recomendados" aria-label="Permalink to &quot;Caminhos de Aprendizagem Recomendados&quot;">​</a></h2><p>Escolha sua ordem de aprendizado com base em suas necessidades:</p><h3 id="caminho-1-migracao-do-claude-code" tabindex="-1">Caminho 1: Migração do Claude Code <a class="header-anchor" href="#caminho-1-migracao-do-claude-code" aria-label="Permalink to &quot;Caminho 1: Migração do Claude Code&quot;">​</a></h3><p>Se você é um usuário migrando do Claude Code:</p><ol><li>Primeiro leia <strong><a href="./claude-code-compatibility/">Compatibilidade com Claude Code</a></strong> para entender como migrar perfeitamente sua configuração existente</li><li>Em seguida, revise <strong><a href="./configuration-reference/">Referência de Configuração</a></strong> para obter uma compreensão mais profunda das opções de configuração disponíveis</li><li>Por fim, aprenda sobre <strong><a href="./builtin-mcps/">MCPs Integrados</a></strong> para entender como configurar recursos adicionais de pesquisa</li></ol><h3 id="caminho-2-personalizacao-profunda" tabindex="-1">Caminho 2: Personalização Profunda <a class="header-anchor" href="#caminho-2-personalizacao-profunda" aria-label="Permalink to &quot;Caminho 2: Personalização Profunda&quot;">​</a></h3><p>Se você deseja personalizar profundamente o comportamento do oh-my-opencode:</p><ol><li>Comece com <strong><a href="./configuration-reference/">Referência de Configuração</a></strong> para entender todos os itens configuráveis</li><li>Aprenda sobre <strong><a href="./builtin-mcps/">MCPs Integrados</a></strong> para configurar recursos de pesquisa e consulta de documentação</li><li>Consulte <strong><a href="./claude-code-compatibility/">Compatibilidade com Claude Code</a></strong> para entender as opções de configuração da camada de compatibilidade</li></ol><h3 id="caminho-3-referencia-rapida" tabindex="-1">Caminho 3: Referência Rápida <a class="header-anchor" href="#caminho-3-referencia-rapida" aria-label="Permalink to &quot;Caminho 3: Referência Rápida&quot;">​</a></h3><p>Se você só precisa consultar informações específicas:</p><ul><li><strong>Perguntas sobre configuração</strong> → Vá diretamente para <strong><a href="./configuration-reference/">Referência de Configuração</a></strong></li><li><strong>Perguntas sobre migração</strong> → Vá diretamente para <strong><a href="./claude-code-compatibility/">Compatibilidade com Claude Code</a></strong></li><li><strong>Configuração de MCP</strong> → Vá diretamente para <strong><a href="./builtin-mcps/">MCPs Integrados</a></strong></li></ul><h2 id="pre-requisitos" tabindex="-1">Pré-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pré-requisitos&quot;">​</a></h2><p>Para este capítulo, recomenda-se que você já tenha:</p><ul><li>✅ Concluído <strong><a href="./../start/installation/">Instalação e Configuração</a></strong></li><li>✅ Entendido os conceitos básicos do <strong><a href="./../start/sisyphus-orchestrator/">Orquestrador Sisyphus</a></strong></li><li>✅ Familiaridade com edição de arquivos de configuração JSON</li></ul><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após concluir este capítulo, você pode:</p><ul><li>🚀 Experimentar <strong><a href="./../advanced/">Recursos Avançados</a></strong> para aprender mais sobre uso avançado</li><li>🔧 Verificar <strong><a href="./../faq/">Perguntas Frequentes</a></strong> para resolver problemas de uso</li><li>📖 Ler <strong><a href="./../changelog/">Changelog</a></strong> para se manter atualizado sobre melhorias de novos recursos</li></ul><div class="tip custom-block"><p class="custom-block-title">Dica</p><p>O conteúdo deste capítulo serve principalmente como material de referência e não precisa ser lido sequencialmente. Você pode consultar as seções relevantes conforme necessário.</p></div>',23)])])}const h=a(d,[["render",n]]);export{m as __pageData,h as default};
